function uid(){return Date.now().toString(36)+Math.random().toString(36).slice(2,8)}
function daysBetween(a:string,b:string){return Math.round((new Date(b).getTime()-new Date(a).getTime())/864e5)}
function today(){return new Date().toISOString().slice(0,10)}

function monthly(s:Sub){return s.cycle==="Monthly"?s.cost:s.cost/12}
function yearly(s:Sub){return s.cycle==="Monthly"?s.cost*12:s.cost}

function wasteScore(s:Sub):number {
  let score=0;
  const daysSince=daysBetween(s.lastUsed,today());
  if(daysSince>30)score+=3;else if(daysSince>14)score+=2;else if(daysSince>7)score+=1;
  if(s.freq==="Rarely")score+=3;else if(s.freq==="Monthly")score+=1;else if(s.freq==="Passive")score+=2;
  if(s.importance==="Low")score+=3;else if(s.importance==="Medium")score+=1;
  if(s.freeAlt)score+=2;
  if(monthly(s)>30)score+=2;else if(monthly(s)>15)score+=1;
  return score;
}

function wasteLevel(s:Sub):"High"|"Medium"|"Low"{const w=wasteScore(s);return w>=8?"High":w>=5?"Medium":"Low"}

function valueScore(s:Sub):number{
  let v=0;
  if(s.freq==="Daily")v+=4;else if(s.freq==="Weekly")v+=3;else if(s.freq==="Monthly")v+=2;else if(s.freq==="Passive")v+=1;
  if(s.importance==="High")v+=4;else if(s.importance==="Medium")v+=2;
  if(monthly(s)<10)v+=2;else if(monthly(s)<25)v+=1;
  if(!s.freeAlt)v+=1;
  return v;
}

function valueTier(s:Sub):"Excellent"|"Good"|"Fair"|"Weak"{const v=valueScore(s);return v>=9?"Excellent":v>=7?"Good":v>=4?"Fair":"Weak"}

function recommendation(s:Sub):"cancel"|"review"|"keep"{const w=wasteLevel(s);return w==="High"?"cancel":w==="Medium"?"review":"keep"}

const WC={High:"#ef4444",Medium:"#eab308",Low:"#22c55e"};
const VC={Excellent:"#22c55e",Good:"#3b82f6",Fair:"#eab308",Weak:"#ef4444"};
const RC={cancel:"#ef4444",review:"#eab308",keep:"#22c55e"};

function useSubs():[Sub[],(s:Sub[])=>void]{
  const[subs,setSubs]=useState<Sub[]>([]);
  useEffect(()=>{try{const d=localStorage.getItem("zoscription");if(d)setSubs(JSON.parse(d))}catch{}},[]);
  const save=useCallback((s:Sub[])=>{setSubs(s);localStorage.setItem("zoscription",JSON.stringify(s))},[]);
  return[subs,save];
}

function useTheme():[boolean,(v:boolean)=>void]{
  const[light,setLight]=useState(()=>{try{return localStorage.getItem("zosc_theme")==="light"}catch{return false}});
  const toggle=(v:boolean)=>{setLight(v);localStorage.setItem("zosc_theme",v?"light":"dark")};
  return[light,toggle];
}

